module piso_shift_register (CLK, RST, LOAD, D, Q);
input CLK, RST, LOAD;
input [7:0] D;
output reg Q;
reg [7:0] unused_shift_reg;

always @(posedge CLK or posedge RST) begin
    if (RST)
        unused_shift_reg <= 8'b00000000;
    else if (LOAD)
        unused_shift_reg <= D;
    else
        unused_shift_reg <= unused_shift_reg >> 1;
end

always @(*) begin
    Q = unused_shift_reg[0];
end

endmodule
